def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        factor = 1
        for depth in range(1, 6):
            temp_residual = residual
            inner_sum = 0
            for j in range(depth):
                if temp_residual > 0:
                    inner_sum += np.exp(-temp_residual * factor)
                else:
                    inner_sum += 10 * factor
                temp_residual /= 2
                factor *= 1.05
            if depth % 2 == 0:
                score += inner_sum * np.log1p(capacity)
            else:
                score -= inner_sum / (np.sqrt(capacity) + 1)
            factor = 1
        if capacity < item * 1.5:
            score *= 1.5
            if capacity < item:
                score += 20
        elif capacity > item * 8 and capacity < item * 15:
            score /= 1.2
            score -= np.log(capacity)
        else:
            score *= 0.95
        if score > 200:
            priorities[i] = 200
        elif score < -100:
            priorities[i] = 0
        else:
            priorities[i] = max(score, 0)
    finite_prios = priorities[np.isfinite(priorities)]
    if finite_prios.size > 0:
        max_val = np.max(finite_prios)
        priorities[np.isinf(priorities)] = max_val + 50
    return priorities
